INSERT INTO "PriceLogs" ("ProductID", "MarketID", "SourceTypeID", "ReportDate", "MinPrice", "MaxPrice", "AvgPrice", "ReportedUnit", "StandardizedPricePerKg", "CreatedAt")
SELECT P."ProductID", M."MarketID", S."SourceTypeID", '2026-04-11', 14319.252, 17501.308, 15910.28, 'KG', 15910.28, CURRENT_TIMESTAMP
FROM "Products" P, "Markets" M, "SourceTypes" S
WHERE P."StandardName" = 'ALAS DE POLLO' AND M."MarketName" = 'Corabastos' AND S."SourceName" = 'Corabastos'
AND NOT EXISTS (
    SELECT 1 FROM "PriceLogs" PL 
    WHERE PL."ProductID" = P."ProductID" AND PL."ReportDate" = '2026-04-11' AND PL."MarketID" = M."MarketID"
);

